window.YPP=window.YPP||{};window.YPP.features=window.YPP.features||{};window.YPP.features.RedirectShorts=class extends window.YPP.features.BaseFeature{constructor(){super("RedirectShorts"),this.checkUrl=this.checkUrl.bind(this)}getConfigKey(){return"redirectShorts"}async enable(){await super.enable(),this.checkUrl()}async disable(){await super.disable()}onPageChange(e){this.isEnabled&&this.checkUrl()}checkUrl(){var r,t;if(!this.isEnabled)return;const e=window.location.href;if(e.includes("/shorts/")){(t=(r=this.utils).log)==null||t.call(r,"Redirecting Short to regular player","RedirectShorts");const s=e.replace("/shorts/","/watch?v=");window.location.replace(s)}}};
